#!/bin/bash
# This file was generated by Cursor AI on 2025-01-24.
#
# Script to process a list of files using c2po.py
# Usage: ./benchmark.sh [options]
#
# Arguments:
#   --quiet: Suppress progress output and progress bars (useful for non-interactive environments)
#   --input-file-list <path>: File containing list of files to process (one per line)
#   --output-json <path>: Output JSON file to write results to
#   --timeout <seconds>: Timeout value for optimize_eqsat in seconds (non-negative integer)
#   --memout <mb>: Memory limit for optimize_eqsat in MB (positive integer)
#   --num-gurobi-threads <n>: Number of Gurobi threads for ILP extraction (non-negative integer, optional)
#   --num-jobs <n>: Number of parallel jobs to run (positive integer)
#   --extraction-method <ilp|greedy>: Extraction method
#   --multi-arity / --no-multi-arity: Enable/disable multi-arity rules
#   --assoc-comm / --no-assoc-comm: Enable/disable associative + commutative rules
#   --control: Control mode (do not run optimize_eqsat)
#   --c2po-path <path>: Path to c2po.py (default: compiler/c2po.py)

set -euo pipefail

# Get script directory
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"

# Print usage/help
print_help() {
    cat >&2 <<'EOF'
Usage: benchmark.sh [options]

Options:
  --input-file-list <path>        File with one input file per line (.c2po or .mltl)
  --output-json <path>            Output JSON file path
  --timeout <seconds>             Non-negative integer timeout (seconds)
  --memout <mb>                   Positive integer memory limit (MB)
  --num-gurobi-threads <n>        Non-negative integer Gurobi thread count (optional, default: 0)
  --num-jobs <n>                  Positive integer number of parallel jobs
  --extraction-method <ilp|greedy>
                                  Extraction method
  --multi-arity | --no-multi-arity
                                  Enable/disable multi-arity
  --assoc-comm | --no-assoc-comm  Enable/disable associative+commutative rules
  --control                        Control mode: skip optimize_eqsat
  --c2po-path <path>               Path to c2po.py (default: compiler/c2po.py)
  --quiet                          Suppress progress output and bars
  -h, --help                       Show this help
EOF
}

# Parse arguments
QUIET=false
INPUT_FILE=""
OUTPUT_FILE=""
TIMEOUT=""
MEMOUT=""
NUM_GUROBI_THREADS="0"
NUM_JOBS=""
EXTRACTION_METHOD=""
CONTROL_ENABLED=false

C2PO_PATH=""

MULTI_ARITY_SET=false
MULTI_ARITY_OPTION=""
MULTI_ARITY_LABEL=""

ASSOC_COMM_SET=false
ASSOC_COMM_OPTION=""
ASSOC_COMM_LABEL=""

while [[ $# -gt 0 ]]; do
    case "$1" in
        --quiet)
            QUIET=true
            shift
            ;;
        --help|-h)
            print_help
            exit 0
            ;;
        --input-file-list)
            INPUT_FILE="${2:-}"
            shift 2
            ;;
        --output-json)
            OUTPUT_FILE="${2:-}"
            shift 2
            ;;
        --timeout)
            TIMEOUT="${2:-}"
            shift 2
            ;;
        --memout)
            MEMOUT="${2:-}"
            shift 2
            ;;
        --num-jobs)
            NUM_JOBS="${2:-}"
            shift 2
            ;;
        --num-gurobi-threads)
            NUM_GUROBI_THREADS="${2:-}"
            shift 2
            ;;
        --extraction-method)
            EXTRACTION_METHOD="${2:-}"
            shift 2
            ;;
        --multi-arity)
            MULTI_ARITY_SET=true
            MULTI_ARITY_OPTION="--multi-arity"
            MULTI_ARITY_LABEL="ma"
            shift
            ;;
        --no-multi-arity)
            MULTI_ARITY_SET=true
            MULTI_ARITY_OPTION="--no-multi-arity"
            MULTI_ARITY_LABEL="noma"
            shift
            ;;
        --assoc-comm)
            ASSOC_COMM_SET=true
            ASSOC_COMM_OPTION="--associative --commutative"
            ASSOC_COMM_LABEL="ac"
            shift
            ;;
        --no-assoc-comm)
            ASSOC_COMM_SET=true
            ASSOC_COMM_OPTION="--no-associative --no-commutative"
            ASSOC_COMM_LABEL="no-ac"
            shift
            ;;
        --control)
            CONTROL_ENABLED=true
            shift
            ;;
        --c2po-path)
            C2PO_PATH="${2:-}"
            shift 2
            ;;
        -*)
            echo "Error: Unknown option '$1'" >&2
            print_help
            exit 1
            ;;
        *)
            echo "Error: Unexpected positional argument '$1'" >&2
            print_help
            exit 1
            ;;
    esac
done

C2PO_PATH="${C2PO_PATH:-$PROJECT_ROOT/compiler/c2po.py}"

# Validate that required flags are present
if [ -z "$INPUT_FILE" ] || [ -z "$OUTPUT_FILE" ] || [ -z "$TIMEOUT" ] || [ -z "$MEMOUT" ] || [ -z "$NUM_JOBS" ] || [ -z "$EXTRACTION_METHOD" ]; then
    echo "Error: missing required options" >&2
    print_help
    exit 1
fi

if [ "$MULTI_ARITY_SET" = false ]; then
    echo "Error: must set either --multi-arity or --no-multi-arity" >&2
    exit 1
fi

if [ "$ASSOC_COMM_SET" = false ]; then
    echo "Error: must set either --assoc-comm or --no-assoc-comm" >&2
    exit 1
fi

# Validate timeout is a non-negative integer
if ! [[ "$TIMEOUT" =~ ^[0-9]+$ ]]; then
    echo "Error: timeout must be a non-negative integer" >&2
    exit 1
fi

# Validate memout is a positive integer
if ! [[ "$MEMOUT" =~ ^[1-9][0-9]*$ ]]; then
    echo "Error: memout must be a positive integer" >&2
    exit 1
fi

# Validate num_jobs is a positive integer
if ! [[ "$NUM_JOBS" =~ ^[1-9][0-9]*$ ]]; then
    echo "Error: num_jobs must be a positive integer" >&2
    exit 1
fi

# Validate num_gurobi_threads is a non-negative integer
if ! [[ "$NUM_GUROBI_THREADS" =~ ^[0-9]+$ ]]; then
    echo "Error: num_gurobi_threads must be a non-negative integer" >&2
    exit 1
fi

# Validate extraction_method
if [ "$EXTRACTION_METHOD" != "ilp" ] && [ "$EXTRACTION_METHOD" != "greedy" ]; then
    echo "Error: extraction_method must be 'ilp' or 'greedy'" >&2
    exit 1
fi

# Convert to absolute paths (resolve relative to current working directory)
if [[ "$INPUT_FILE" != /* ]]; then
    INPUT_FILE="$PWD/$INPUT_FILE"
fi
INPUT_FILE="$(cd "$(dirname "$INPUT_FILE")" && pwd)/$(basename "$INPUT_FILE")"

if [[ "$OUTPUT_FILE" != /* ]]; then
    OUTPUT_FILE="$PWD/$OUTPUT_FILE"
fi
# Compute output directory from the raw path first so we can create it
# before canonicalizing (dirname may not exist yet).
OUTPUT_DIR="$(dirname "$OUTPUT_FILE")"
if [ ! -d "$OUTPUT_DIR" ]; then
    mkdir -p "$OUTPUT_DIR" || {
        echo "Error: Failed to create output directory '$OUTPUT_DIR'" >&2
        exit 1
    }
fi

# Convert output path to canonical absolute path now that directory exists.
OUTPUT_FILE="$(cd "$OUTPUT_DIR" && pwd)/$(basename "$OUTPUT_FILE")"
OUTPUT_DIR="$(dirname "$OUTPUT_FILE")"

# Verify output directory is writable
if [ ! -w "$OUTPUT_DIR" ]; then
    echo "Error: Output directory '$OUTPUT_DIR' is not writable" >&2
    exit 1
fi

# Resolve c2po_path (CLI argument) - resolve relative to project root if not absolute
if [[ "$C2PO_PATH" != /* ]]; then
    # If not absolute, resolve relative to project root
    C2PO_PATH="$PROJECT_ROOT/$C2PO_PATH"
fi
# Convert to absolute path
C2PO_PATH="$(cd "$(dirname "$C2PO_PATH")" && pwd)/$(basename "$C2PO_PATH")"

# Check if input file exists
if [ ! -f "$INPUT_FILE" ]; then
    echo "Error: Input file '$INPUT_FILE' does not exist" >&2
    exit 1
fi

# Check if c2po.py exists
if [ ! -f "$C2PO_PATH" ]; then
    echo "Error: c2po.py file '$C2PO_PATH' does not exist" >&2
    exit 1
fi

# Check if GNU parallel is available
if ! command -v parallel &> /dev/null; then
    echo "Error: GNU parallel is not installed. Please install it first." >&2
    exit 1
fi

# Create temporary directory for template files
TEMPLATE_TMPDIR=$(mktemp -d)
# Ensure temporary directory created by this script is cleaned up
trap "rm -rf $TEMPLATE_TMPDIR" EXIT
# TEMPLATE_TMPDIR="${PROJECT_ROOT}/tmp/template_${BASHPID}"
# mkdir -p "$TEMPLATE_TMPDIR"

# Function to process a single file
process_file() {
    local input_file="$1"
    local timeout="$2"
    local memout="$3"
    local c2po_path="$4"
    local tmpdir="$5"
    local extraction_method="$6"
    local multi_arity_option="$7"
    local num_gurobi_threads="$8"
    local job_slot="$9"
    # Use environment variables for all options and labels that may contain spaces or special characters
    # This prevents argument splitting issues when passed through parallel
    local assoc_comm_option="${ASSOC_COMM_OPTION}"
    local control_enabled="${CONTROL_ENABLED}"
    # Use environment variables for labels to avoid argument position issues
    local extraction_method_label="${EXTRACTION_METHOD}"
    local multi_arity_label="${MULTI_ARITY_LABEL}"
    local assoc_comm_label="${ASSOC_COMM_LABEL}"
    
    # Get absolute path of input file
    local abs_input_file
    if [[ "$input_file" = /* ]]; then
        abs_input_file="$input_file"
    else
        abs_input_file="$(cd "$(dirname "$input_file")" && pwd)/$(basename "$input_file")"
    fi
    
    # Check if file exists
    if [ ! -f "$abs_input_file" ]; then
        echo "Error: File '$input_file' does not exist" >&2
        return 1
    fi
    
    # Validate tmpdir is set
    if [ -z "$tmpdir" ] || [ ! -d "$tmpdir" ]; then
        echo "Error: Invalid temporary directory: '$tmpdir'" >&2
        return 1
    fi
    
    # Determine file type and create appropriate template
    local basename_file=$(basename "$abs_input_file")
    local temp_template="$tmpdir/template_${BASHPID}_$(basename "$abs_input_file" | tr '/' '_').cmd"
    
    # Convert to absolute path
    temp_template="$(cd "$(dirname "$temp_template")" && pwd)/$(basename "$temp_template")"
    
    # Build the optimize_eqsat line, commenting it out in control mode
    local optimize_line
    local run_label
    if [ "$control_enabled" = true ]; then
        optimize_line=""
        run_label="control"
    else
        run_label="${extraction_method_label}-${assoc_comm_label}"
        optimize_line="optimize_eqsat --extraction-method $extraction_method $multi_arity_option $assoc_comm_option --egglog-max-time $timeout --egglog-max-memory $memout --gurobi-max-time $timeout --gurobi-max-memory $memout --num-gurobi-threads $num_gurobi_threads"
    fi
    
    # Generate template by writing the embedded template contents directly
    if [[ "$basename_file" == *.c2po ]]; then
        # For .c2po files, prepend enable_booleanizer and parse_c2po
        cat > "$temp_template" <<EOF
suppress_warnings
enable_booleanizer
parse_c2po $abs_input_file

type_check
desugar
optimize_cse
compute_atomics

$optimize_line
optimize_cse
compute_scq_sizes

print_stats "    {\n"
print_stats "        \"filename\": \"%F\",\n"
print_stats "        \"${run_label}\": {\n"
print_stats "            \"formula\": \"%f0\",\n"
print_stats "            \"scq\": %scq,\n"
print_stats "            \"dag-size\": %dagsize,\n"
print_stats "            \"num-temporal-operators\": %numtlo,\n"
print_stats "            \"egglog-status\": \"%eqsatstatus\",\n"
print_stats "            \"egglog-encoding-time\": %eqsatenc,\n"
print_stats "            \"egglog-solver-time\": %eqsattime,\n"
print_stats "            \"num-eclasses\": %eqsateclasses,\n"
print_stats "            \"num-enodes\": %eqsatenodes,\n"
print_stats "            \"gurobi-status\": \"%eqsatgurstatus\",\n"
print_stats "            \"gurobi-encoding-time\": %eqsatgurenc,\n"
print_stats "            \"gurobi-solving-time\": %eqsatgurtime,\n"

multi_operators_to_binary
generate_map
assemble /dev/null
print_stats "            \"num-tl-temporal-instructions\": %asmtltemp,\n"
print_stats "            \"num-tl-instructions\": %asmtl,\n"

remove_release_operators 
convert_atomics_to_signals
generate_sabre_code --word-size 8 /dev/null
print_stats "            \"sabre-total-bytes\": %sabrebytes\n"

print_stats "        }\n"
print_stats "    },\n"
EOF
    elif [[ "$basename_file" == *.mltl ]]; then
        # For .mltl files, prepend parse_mltl
        cat > "$temp_template" <<EOF
suppress_warnings
parse_mltl $abs_input_file

type_check
desugar
optimize_cse
compute_atomics

$optimize_line
optimize_cse
compute_scq_sizes

print_stats "    {\n"
print_stats "        \"filename\": \"%F\",\n"
print_stats "        \"${run_label}\": {\n"
print_stats "            \"formula\": \"%f0\",\n"
print_stats "            \"scq\": %scq,\n"
print_stats "            \"dag-size\": %dagsize,\n"
print_stats "            \"num-temporal-operators\": %numtlo,\n"
print_stats "            \"egglog-status\": \"%eqsatstatus\",\n"
print_stats "            \"egglog-encoding-time\": %eqsatenc,\n"
print_stats "            \"egglog-solver-time\": %eqsattime,\n"
print_stats "            \"num-eclasses\": %eqsateclasses,\n"
print_stats "            \"num-enodes\": %eqsatenodes,\n"
print_stats "            \"gurobi-status\": \"%eqsatgurstatus\",\n"
print_stats "            \"gurobi-encoding-time\": %eqsatgurenc,\n"
print_stats "            \"gurobi-solving-time\": %eqsatgurtime,\n"

multi_operators_to_binary
assemble /dev/null
print_stats "            \"num-tl-temporal-instructions\": %asmtltemp,\n"
print_stats "            \"num-tl-instructions\": %asmtl,\n"

remove_release_operators
generate_sabre_code --word-size 8 /dev/null
print_stats "            \"sabre-total-bytes\": %sabrebytes\n"

print_stats "        }\n"
print_stats "    },\n"
EOF
    else
        echo "Error: File '$input_file' must have .c2po or .mltl extension" >&2
        return 1
    fi

    # Copy template to input file location for debugging (only if directory is writable)
    # This may fail in Apptainer if the directory isn't bind-mounted, so don't fail on error
    # cp "$temp_template" "$abs_input_file.cmd" 2>/dev/null || true

    # Run c2po.py and capture output
    # Change to compiler directory so Python can find the c2po module
    local compiler_dir="$(dirname "$c2po_path")"
    cd "$compiler_dir"
    
    # Run c2po and capture stdout (JSON output from print_stats)
    # Capture stderr to a temp file for debugging and save it to a file on error, but don't show it in parallel output
    local stderr_file="$tmpdir/stderr_${BASHPID}_$(basename "$abs_input_file" | tr '/' '_').log"
    if ! python3 "$(basename "$c2po_path")" -s "$temp_template" 2>"$stderr_file"; then
        # If there's an error, include it in the error message for debugging
        local error_msg="Processing failed"
        if [ -s "$stderr_file" ]; then
            error_msg="Processing failed: $stderr_file"
            cp "$stderr_file" "$abs_input_file.stderr.log"
        fi
        echo "ERROR,$input_file,$error_msg" >&2
        # Also output to stdout so it appears in JSON (as an error line)
        echo "ERROR,$input_file,$error_msg"
        return 1
    fi
}

# Export function and variables for parallel
export -f process_file
export C2PO_PATH TEMPLATE_TMPDIR TIMEOUT MEMOUT EXTRACTION_METHOD MULTI_ARITY_OPTION ASSOC_COMM_OPTION MULTI_ARITY_LABEL ASSOC_COMM_LABEL CONTROL_ENABLED NUM_JOBS NUM_GUROBI_THREADS

echo "{" > "$OUTPUT_FILE"
echo "  \"results\": [" >> "$OUTPUT_FILE"

# Process files in parallel with progress bar
# Use --progress/--bar to show progress bar (unless --quiet is set)
# Use --line-buffer to show output as it arrives
# Use --jobs to limit number of parallel jobs
# Filter out empty lines and whitespace-only lines
# Collect all outputs to JSON file
PARALLEL_OPTS=()
if [ "$QUIET" = false ]; then
    PARALLEL_OPTS+=(--progress --bar)
fi
PARALLEL_OPTS+=(--line-buffer --jobs "$NUM_JOBS")

grep -v '^[[:space:]]*$' "$INPUT_FILE" | parallel "${PARALLEL_OPTS[@]}" \
    process_file {} "$TIMEOUT" "$MEMOUT" "$C2PO_PATH" "$TEMPLATE_TMPDIR" "$EXTRACTION_METHOD" "$MULTI_ARITY_OPTION" "$NUM_GUROBI_THREADS" {%} >> "$OUTPUT_FILE"

# Remove trailing comma from last line only
sed -i '$s/,$//' "$OUTPUT_FILE"
echo "  ]" >> "$OUTPUT_FILE"
echo "}" >> "$OUTPUT_FILE"

if [ "$QUIET" = false ]; then
    echo "Processing complete. Results saved to: $OUTPUT_FILE"
fi
